onFilesSelected:
{{
  (async () => {
    try {
      // 1. Get the content from the file
      const base64String = fpSyncImport.files[0].data.split(",")[1];
      const payload = JSON.parse(atob(base64String));

      showAlert(`Importing: ${payload.metadata?.employee_name || 'DSE Backup'}...`, "info");

      // 2. Send it to the server
      await apiManualSync.run({ 
        ...payload, 
        sync_source: 'MANUAL_IMPORT' 
      });

      showAlert("✅ Manual Sync Success! Data is now in your database.", "success");



    } catch (err) {
      showAlert("❌ Error: Invalid sync file format.", "error");
    }
  })()
}}
